import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 18 },
    { day: 'Tue', icon: '☁️', high: 22, low: 16 },
    { day: 'Wed', icon: '🌧️', high: 18, low: 14 },
    { day: 'Thu', icon: '☁️', high: 20, low: 15 },
    { day: 'Fri', icon: '☀️', high: 23, low: 17 },
  ],
}: Props) {
  const conditionStr = String(condition);
  const ariaLabel = 'Weather condition: ' + conditionStr;

  return (
    <Card padding={24} shadow="md" border={true}>
      <Stack direction="vertical" gap={16}>
        {/* City Name */}
        <Text
          variant="h2"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          {city}
        </Text>

        {/* Current Temperature & Condition */}
        <Stack direction="vertical" gap={12} align="start">
          {/* Large Temperature Value */}
          <div
            style={{
              fontSize: 'var(--ggui-font-size-3xl, 30px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              lineHeight: 1,
            }}
          >
            {temperature}°{unit}
          </div>

          {/* Condition with Icon */}
          <Row gap={12} align="center">
            <div
              style={{
                fontSize: '28px',
                lineHeight: 1,
              }}
              aria-label={ariaLabel}
            >
              {/* Icon mapping based on condition */}
              {condition === 'Sunny' && '☀️'}
              {condition === 'Cloudy' && '☁️'}
              {condition === 'Rainy' && '🌧️'}
              {condition === 'Snowy' && '❄️'}
              {condition === 'Stormy' && '⛈️'}
              {condition === 'Windy' && '💨'}
              {!['Sunny', 'Cloudy', 'Rainy', 'Snowy', 'Stormy', 'Windy'].includes(condition) && '🌤️'}
            </div>
            <Text
              variant="h3"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {condition}
            </Text>
          </Row>
        </Stack>

        {/* Metrics Row: Humidity & Wind Speed */}
        <Row gap={32} align="center" justify="start">
          {/* Humidity */}
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              weight="normal"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-base, 16px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                color: 'var(--ggui-color-onSurface, #18181b)',
              }}
            >
              {humidity}%
            </div>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4}>
            <Text
              variant="caption"
              weight="normal"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-base, 16px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                color: 'var(--ggui-color-onSurface, #18181b)',
              }}
            >
              {windSpeed} km/h
            </div>
          </Stack>
        </Row>

        {/* Divider */}
        <Divider orientation="horizontal" margin={8} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            weight="semibold"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            5-Day Forecast
          </Text>

          {/* Forecast Items in Horizontal Row */}
          <Row gap={8} justify="between" wrap={true}>
            {forecast.map((item, index) => (
              <Box
                key={index}
                padding="var(--ggui-spacing-2, 8px)"
                style={{
                  flex: '1 1 18%',
                  minWidth: '60px',
                  textAlign: 'center',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
              >
                <Stack direction="vertical" gap={6} align="center">
                  {/* Day Name */}
                  {item.day && (
                    <Text
                      variant="caption"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {item.day}
                    </Text>
                  )}

                  {/* Weather Icon */}
                  {item.icon && (
                    <div
                      style={{
                        fontSize: '18px',
                        lineHeight: 1,
                      }}
                    >
                      {item.icon}
                    </div>
                  )}

                  {/* High/Low Temps */}
                  <Row gap={4} align="center" justify="center">
                    {item.high !== undefined && (
                      <Text
                        variant="caption"
                        weight="semibold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.high}°
                      </Text>
                    )}
                    {item.low !== undefined && (
                      <Text
                        variant="caption"
                        weight="normal"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {item.low}°
                      </Text>
                    )}
                  </Row>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider, Box, Spacer, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('partly')) return '⛅';
  if (c.includes('cloudy') || c.includes('overcast')) return '🌥️';
  if (c.includes('rain')) return '🌧️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('snow')) return '🌨️';
  if (c.includes('fog') || c.includes('mist')) return '🌫️';
  if (c.includes('wind')) return '💨';
  return '🌡️';
}

export default function GeneratedComponent({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 74, low: 58 },
    { day: 'Tue', icon: '⛅', high: 70, low: 56 },
    { day: 'Wed', icon: '🌧️', high: 63, low: 52 },
    { day: 'Thu', icon: '🌥️', high: 66, low: 54 },
    { day: 'Fri', icon: '☀️', high: 75, low: 60 },
  ],
}: Props) {
  const { motionEnabled } = useMotion();
  const windUnit = unit === 'C' ? 'km/h' : 'mph';
  const unitLabel = unit === 'C' ? 'Celsius' : 'Fahrenheit';
  const regionLabel = 'Weather for ' + city;
  const tempLabel = temperature + ' degrees ' + unitLabel;

  return (
    <>
      <MotionKeyframes />
      <div
        role="region"
        aria-label={regionLabel}
        style={{
          maxWidth: '420px',
          width: '100%',
        }}
      >
        <Card
          shadow="md"
          border={true}
          padding={0}
          style={{
            overflow: 'hidden',
            borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
            animation: motionEnabled ? animation.fadeIn : 'none',
          }}
        >
          {/* === HEADER: Gradient background with temp + condition === */}
          <div
            style={{
              background: 'linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))',
              padding: 'var(--ggui-spacing-6, 24px)',
            }}
          >
            <Stack direction="vertical" gap={12}>
              {/* City name */}
              <Text
                variant="label"
                style={{ color: 'var(--ggui-color-onPrimary, #ffffff)', opacity: 0.85 }}
              >
                <span aria-hidden="true">📍</span>{' '}{city}
              </Text>

              {/* Temperature + condition emoji row */}
              <Row align="end" gap={8}>
                <span
                  style={{
                    fontSize: '64px',
                    fontWeight: 700,
                    color: 'var(--ggui-color-onPrimary, #ffffff)',
                    lineHeight: 1,
                    letterSpacing: '-0.025em',
                    fontFamily: 'inherit',
                  }}
                  aria-label={tempLabel}
                >
                  {temperature}°{unit}
                </span>
                <Spacer />
                <Stack direction="vertical" align="center" gap={2}>
                  <span
                    aria-hidden="true"
                    style={{ fontSize: '48px', lineHeight: 1 }}
                  >
                    {getConditionEmoji(condition)}
                  </span>
                  <Text
                    variant="caption"
                    style={{ color: 'var(--ggui-color-onPrimary, #ffffff)', opacity: 0.9 }}
                  >
                    {condition}
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </div>

          {/* === DETAILS SECTION: Humidity + Wind Speed === */}
          <Box
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Row gap={0} justify="around">
              {/* Humidity stat */}
              <Stack direction="vertical" align="center" gap={4}>
                <Text
                  variant="caption"
                  style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                >
                  <span aria-hidden="true">💧</span>{' '}Humidity
                </Text>
                <Text
                  variant="body"
                  style={{
                    fontWeight: 600,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {humidity}%
                </Text>
              </Stack>

              {/* Wind speed stat */}
              <Stack direction="vertical" align="center" gap={4}>
                <Text
                  variant="caption"
                  style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                >
                  <span aria-hidden="true">💨</span>{' '}Wind Speed
                </Text>
                <Text
                  variant="body"
                  style={{
                    fontWeight: 600,
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {windSpeed} {windUnit}
                </Text>
              </Stack>
            </Row>
          </Box>

          <Divider orientation="horizontal" margin={0} />

          {/* === FORECAST SECTION: 5-day strip === */}
          <Box
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Stack direction="vertical" gap={12}>
              <Text
                variant="label"
                style={{
                  fontWeight: 600,
                  color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                }}
              >
                5-Day Forecast
              </Text>

              <Row justify="between" gap={4}>
                {forecast.map((item, index) => (
                  <Stack
                    key={index}
                    direction="vertical"
                    align="center"
                    gap={4}
                    style={{ flex: 1 }}
                  >
                    {/* Day name */}
                    <Text
                      variant="caption"
                      style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                    >
                      {item.day ?? '—'}
                    </Text>

                    {/* Day weather icon */}
                    <span
                      aria-hidden="true"
                      style={{ fontSize: '24px', lineHeight: 1 }}
                    >
                      {item.icon ?? '🌡️'}
                    </span>

                    {/* High temperature */}
                    <Text
                      variant="caption"
                      style={{
                        fontWeight: 600,
                        color: 'var(--ggui-color-onSurface, #18181b)',
                      }}
                    >
                      {item.high != null ? item.high + '°' : '—'}
                    </Text>

                    {/* Low temperature */}
                    <Text
                      variant="caption"
                      style={{ color: 'var(--ggui-color-onSurfaceVariant, #52525b)' }}
                    >
                      {item.low != null ? item.low + '°' : '—'}
                    </Text>
                  </Stack>
                ))}
              </Row>
            </Stack>
          </Box>
        </Card>
      </div>
    </>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

/**
 * Props Contract for the WeatherCard component.
 */
interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to get a simple emoji based on condition string
 */
const getWeatherEmoji = (condition: string = '') => {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('showers')) return '🌧️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('thunder')) return '⛈️';
  if (c.includes('mist') || c.includes('fog')) return '🌫️';
  return '🌡️';
};

/**
 * A reusable Weather Card template component.
 * Displays current weather metrics and a 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '☁️', high: 70, low: 58 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 55 },
    { day: 'Thu', icon: '☀️', high: 72, low: 59 },
    { day: 'Fri', icon: '☀️', high: 74, low: 61 },
  ]
}: Props) {
  // CSS Variable fallbacks for safety
  const labelColor = 'var(--ggui-color-onSurfaceVariant, #52525b)';
  const mainTextColor = 'var(--ggui-color-onSurface, #18181b)';
  const accentColor = 'var(--ggui-color-primary, #0284c7)';
  const cardBg = 'var(--ggui-color-surface, #ffffff)';
  const headerBg = 'var(--ggui-color-surfaceContainerLow, #f0f9ff)';
  const footerBg = 'var(--ggui-color-surfaceContainerLowest, #fafafa)';

  return (
    <Card 
      variant="elevated"
      padding={0}
      style={{ 
        overflow: 'hidden', 
        maxWidth: 450, 
        backgroundColor: cardBg,
        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-border-radius-xl, 16px)',
        margin: 'var(--ggui-spacing-4, 16px)'
      }}
    >
      <Stack gap={0}>
        {/* Header Section: City and Condition */}
        <Box 
          padding="var(--ggui-spacing-6, 24px)" 
          style={{ backgroundColor: headerBg }}
        >
          <Row justify="between" align="start">
            <Stack gap={4}>
              <Text variant="h2" weight="bold" color={mainTextColor}>
                {city}
              </Text>
              <Text variant="bodyLarge" color={labelColor}>
                {condition}
              </Text>
            </Stack>
            <Text style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', lineHeight: 1 }}>
              {getWeatherEmoji(condition)}
            </Text>
          </Row>
        </Box>

        {/* Main Section: Temperature and Details */}
        <Box padding="var(--ggui-spacing-6, 24px)">
          <Stack gap={24}>
            <Row align="center" justify="center">
              <Text 
                variant="h1" 
                weight="bold" 
                style={{ 
                  fontSize: 'calc(var(--ggui-font-size-5xl, 48px) * 1.5)',
                  lineHeight: 1
                }}
                color={accentColor}
              >
                {Math.round(temperature)}{unit}
              </Text>
            </Row>

            <Row justify="around" align="center">
              <Stack align="center" gap={4} style={{ flex: 1 }}>
                <Text variant="caption" color={labelColor} weight="bold" style={{ letterSpacing: '0.05em' }}>
                  HUMIDITY
                </Text>
                <Text variant="body" weight="semibold" color={mainTextColor}>
                  {humidity}%
                </Text>
              </Stack>

              <div style={{ width: 1, height: 40, backgroundColor: 'var(--ggui-color-outlineVariant, #e4e4e7)', opacity: 0.5 }} />

              <Stack align="center" gap={4} style={{ flex: 1 }}>
                <Text variant="caption" color={labelColor} weight="bold" style={{ letterSpacing: '0.05em' }}>
                  WIND
                </Text>
                <Text variant="body" weight="semibold" color={mainTextColor}>
                  {windSpeed} mph
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Box>

        <Divider margin={0} />

        {/* Footer Section: 5-Day Forecast Strip */}
        <Box 
          padding="var(--ggui-spacing-4, 16px)" 
          style={{ backgroundColor: footerBg }}
        >
          <Row justify="between" align="center" style={{ gap: 'var(--ggui-spacing-2, 8px)' }}>
            {forecast.slice(0, 5).map((item, index) => (
              <Stack 
                key={index} 
                align="center" 
                gap={8} 
                style={{ flex: 1, minWidth: 64 }}
              >
                <Text variant="caption" color={labelColor} weight="bold">
                  {item.day ? item.day.toUpperCase() : ''}
                </Text>
                <Text style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', lineHeight: 1 }}>
                  {item.icon || getWeatherEmoji('')}
                </Text>
                <Stack gap={2} align="center">
                  <Text variant="bodySmall" weight="bold" color={mainTextColor}>
                    {item.high}{unit}
                  </Text>
                  <Text variant="caption" color={labelColor}>
                    {item.low}{unit}
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Row>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Card, Stack, Text, Button, Input } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; electronConfiguration?: string; row?: number; col?: number }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-container)',
  'alkaline-earth': 'var(--ggui-color-secondary-container)',
  'transition-metal': 'var(--ggui-color-surface-variant)',
  'post-transition-metal': 'var(--ggui-color-info-container)',
  'metalloid': 'var(--ggui-color-warning-container)',
  'nonmetal': 'var(--ggui-color-error-container)',
  'halogen': 'var(--ggui-color-accent-container)',
  'noble-gas': 'var(--ggui-color-success-container)',
  'lanthanide': 'var(--ggui-color-outline-variant)',
  'actinide': 'var(--ggui-color-surface-container-high)',
};

const CATEGORY_LABELS: Record<string, string> = {
  'alkali-metal': 'Alkali Metal',
  'alkaline-earth': 'Alkaline Earth',
  'transition-metal': 'Transition Metal',
  'post-transition-metal': 'Post-transition Metal',
  'metalloid': 'Metalloid',
  'nonmetal': 'Nonmetal',
  'halogen': 'Halogen',
  'noble-gas': 'Noble Gas',
  'lanthanide': 'Lanthanide',
  'actinide': 'Actinide',
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lower = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        (el.name && el.name.toLowerCase().includes(lower)) ||
        (el.symbol && el.symbol.toLowerCase().includes(lower))
    );
  }, [elements, searchTerm]);

  return (
    <Stack gap="xl" padding="xl" style={{ backgroundColor: 'var(--ggui-color-surface)', minHeight: '100vh' }}>
      <Stack direction="row" align="center" justify="space-between" wrap="wrap" gap="md">
        <Text variant="headline-medium" weight="bold">Periodic Table</Text>
        <Stack gap="xs" style={{ width: 'var(--ggui-size-1000, 320px)' }}>
          <Text as="label" htmlFor="search-input">Search Elements</Text>
          <Input id="search-input" label="Search Elements" placeholder="Search..." value={searchTerm} onChange={setSearchTerm} />
        </Stack>
      </Stack>

      <Stack direction="row" gap="md" wrap="wrap" justify="center">
        {Object.keys(CATEGORY_COLORS).map((cat) => (
          <Stack key={cat} direction="row" align="center" gap="xs">
            <div
              style={{
                width: 'var(--ggui-spacing-md, 16px)',
                height: 'var(--ggui-spacing-md, 16px)',
                borderRadius: 'var(--ggui-radius-xs, 4px)',
                backgroundColor: CATEGORY_COLORS[cat],
                border: '1px solid var(--ggui-color-outline)',
              }}
            />
            <Text variant="label-small">{CATEGORY_LABELS[cat] || cat}</Text>
          </Stack>
        ))}
      </Stack>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
          gap: 'var(--ggui-spacing-xs, 4px)',
          width: '100%',
          overflowX: 'auto',
          padding: 'var(--ggui-spacing-sm, 8px)',
        }}
      >
        {elements.map((el) => {
          const isSelected = selectedElement === el;
          const isFiltered = filteredElements.includes(el);
          return (
            <div
              key={String(el.atomicNumber) + String(el.symbol)}
              style={{
                gridColumn: el.col,
                gridRow: el.row,
                opacity: isFiltered ? 1 : 0.2,
                transition: 'opacity 0.2s ease',
              }}
            >
              <Button
                variant="ghost"
                fullWidth
                onClick={() => setSelectedElement(el)}
                style={{
                  height: 'var(--ggui-size-900, 72px)',
                  padding: 'var(--ggui-spacing-xs, 4px)',
                  backgroundColor: CATEGORY_COLORS[el.category || ''] || 'var(--ggui-color-surface-container)',
                  border: isSelected ? '2px solid var(--ggui-color-primary)' : '1px solid var(--ggui-color-outline-variant)',
                  borderRadius: 'var(--ggui-radius-sm, 4px)',
                  display: 'flex',
                  flexDirection: 'column',
                  position: 'relative',
                  overflow: 'hidden',
