                  <Text variant="headline-small" weight="bold">{selectedElement.symbol}</Text>
                </div>
                <Stack gap="none">
                  <Text variant="headline-medium">{selectedElement.name}</Text>
                  <Text variant="body-large" color="secondary">{CATEGORY_LABELS[selectedElement.category || ''] || selectedElement.category}</Text>
                </Stack>
              </Stack>
              <Button variant="ghost" onClick={() => setSelectedElement(null)}>Close</Button>
            </Stack>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 'var(--ggui-spacing-lg, 24px)' }}>
              <Stack gap="xs">
