                <Text variant="body-large">{String(selectedElement.atomicWeight)}</Text>
              </Stack>
              <Stack gap="xs">
                <Text variant="label-large" color="secondary">Electron Configuration</Text>
                <Text variant="body-large">{selectedElement.electronConfiguration}</Text>
              </Stack>
              <Stack gap="xs">
                <Text variant="label-large" color="secondary">Classification</Text>
                <Text variant="body-large">{CATEGORY_LABELS[selectedElement.category || ''] || selectedElement.category}</Text>
              </Stack>
            </div>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Stack, Text, Card, Input, Button } from '@ggui-ai/design/primitives';

interface Message {
  text?: string;
  sender?: string;
  timestamp?: string;
}

interface User {
  name?: string;
  avatar?: string;
}

interface Props {
  title?: string;
  user?: User;
  initialMessages?: Message[];
  onSendMessage?: (payload: { text: string }) => void;
}

export default function RealTimeChat(props: Props) {
  const { title = 'Conversation', user = { name: 'You' }, initialMessages = [], onSendMessage } = props;
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const typingTimeoutRef = useRef<number | null>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, typingUser]);

  useEffect(() => {
    const handleData = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (detail?.type === 'message') {
        setMessages(prev => [...prev, { text: detail.text, sender: detail.sender, timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
        setTypingUser(null);
      } else if (detail?.type === 'typing') {
        setTypingUser(detail.sender);
        if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => setTypingUser(null), 3000) as any;
      }
    };
    addEventListener('ggui:agent-data', handleData);
    return () => removeEventListener('ggui:agent-data', handleData);
  }, []);

  const handleAction = () => {
    const text = inputValue.trim();
    if (!text) return;
    setMessages(prev => [...prev, { text, sender: user.name, timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
    if (onSendMessage) onSendMessage({ text });
    setInputValue('');
  };

  return (
    <Card variant="elevated" style={{ height: 'var(--ggui-spacing-huge, 500px)', display: 'flex', flexDirection: 'column', border: '1px solid var(--ggui-color-outline)' }}>
      <Stack direction="row" justify="space-between" align="center" style={{ padding: 'var(--ggui-spacing-md, 12px) var(--ggui-spacing-lg, 16px)', borderBottom: '1px solid var(--ggui-color-outline)' }}>
        <Text variant="body-large" style={{ fontWeight: 600 }}>{title}</Text>
        <Text variant="body-small" style={{ opacity: 0.7 }}>Online</Text>
      </Stack>
      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-lg, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-md, 12px)' }}>
        {messages.map((m, i) => (
          <Stack key={i} align={m.sender === user.name ? 'flex-end' : 'flex-start'}>
            <Stack gap="var(--ggui-spacing-xs, 4px)" align={m.sender === user.name ? 'flex-end' : 'flex-start'}>
              <Text variant="label-small" style={{ opacity: 0.6 }}>{m.sender} • {m.timestamp}</Text>
              <div style={{ padding: 'var(--ggui-spacing-sm, 8px) var(--ggui-spacing-md, 12px)', borderRadius: 'var(--ggui-radius-md, 12px)', background: m.sender === user.name ? 'var(--ggui-color-primary)' : 'var(--ggui-color-surface-container-high)', color: m.sender === user.name ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurface)' }}>
                <Text variant="body-medium">{m.text}</Text>
              </div>
            </Stack>
          </Stack>
        ))}
        {typingUser && <Text variant="body-small" style={{ fontStyle: 'italic', opacity: 0.7 }}>{typingUser} is typing...</Text>}
      </div>
      <Stack direction="row" gap="var(--ggui-spacing-sm, 8px)" align="flex-end" style={{ padding: 'var(--ggui-spacing-lg, 16px)', borderTop: '1px solid var(--ggui-color-outline)' }}>
        <Stack style={{ flex: 1 }} gap="var(--ggui-spacing-xs, 4px)">
          <Text as="label" htmlFor="chat-input" variant="label-small">Chat</Text>
          <Input id="chat-input" label="Chat" value={inputValue} onChange={(value: string) => setInputValue(value)} onKeyDown={(e: any) => e.key === 'Enter' && handleAction()} />
        </Stack>
        <Button variant="filled" onClick={handleAction} disabled={!inputValue.trim()}>Send</Button>
      </Stack>
    </Card>
  );
}

/**
 * __GGUI_STREAM_SPEC__
 * {
 *   "events": {
 *     "message": { "schema": { "type": "object", "properties": { "text": { "type": "string" }, "sender": { "type": "string" } } } },
 *     "typing": { "schema": { "type": "object", "properties": { "sender": { "type": "string" } } } }
 *   }
 * }
 * __GGUI_STREAM_SPEC_END__
 */

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Badge,
  Divider
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
}

/**
 * __GGUI_STREAM_SPEC__
 * {
 *   "events": {
 *     "price-update": {
 *       "schema": {
 *         "type": "object",
 *         "properties": {
 *           "symbol": { "type": "string" },
 *           "price": { "type": "number" },
 *           "change": { "type": "number" },
 *           "changePercent": { "type": "number" }
 *         }
 *       }
 *     }
 *   }
 * }
 * __GGUI_STREAM_SPEC_END__
 */

export default function StockTickerDashboard({
  stocks = [
    { symbol: 'AAPL', name: 'Apple Inc.', price: 175.22, change: 1.45, changePercent: 0.83 },
    { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 142.15, change: -0.65, changePercent: -0.46 },
    { symbol: 'TSLA', name: 'Tesla, Inc.', price: 238.45, change: 12.30, changePercent: 5.44 },
    { symbol: 'MSFT', name: 'Microsoft Corp.', price: 374.07, change: 2.15, changePercent: 0.58 },
    { symbol: 'AMZN', name: 'Amazon.com Inc.', price: 145.18, change: -1.12, changePercent: -0.76 },
    { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 485.45, change: 15.20, changePercent: 3.23 }
  ]
}: Props) {
  const [marketData, setMarketData] = useState(stocks);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(new Date());
  const [currentTime, setCurrentTime] = useState(new Date());
  const [updatedSymbol, setUpdatedSymbol] = useState<string | null>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail || {};
      const type = detail.type;
      const data = detail.data;

      if (type === 'price-update' && data && data.symbol) {
        setMarketData((prev) =>
          prev.map((stock) =>
            stock.symbol === data.symbol
              ? { ...stock, ...data }
              : stock
          )
        );
        setLastUpdated(new Date());
        setUpdatedSymbol(data.symbol);
        const timeout = setTimeout(() => setUpdatedSymbol(null), 1000);
        return () => clearTimeout(timeout);
      }
    };

    if (typeof globalThis !== 'undefined') {
      globalThis.addEventListener('ggui:agent-data', handleAgentData);
      return () => globalThis.removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const formatCurrency = (value?: number) => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value || 0);

  const formatPercent = (value?: number) => {
    const val = value || 0;
    const sign = val > 0 ? "+" : "";
    return sign + val.toFixed(2) + "%";
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap={24}>

        <Row justify="between" align="center">
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Live exchange data feed
            </Text>
          </Stack>
          <Card 
            variant="flat" 
            padding="8px 16px" 
            style={{ backgroundColor: 'var(--ggui-color-surfaceContainer)' }}
          >
            <Text weight="medium">
              {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </Text>
          </Card>
        </Row>

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
          gap: 'var(--ggui-spacing-4)',
          width: '100%'
        }}>
          {marketData.map((stock) => {
            const isPositive = (stock.changePercent || 0) >= 0;
            const isJustUpdated = updatedSymbol === stock.symbol;
            const trendColor = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';

            return (
              <Card 
                key={stock.symbol} 
                padding={20}
                style={{
                  transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                  border: isJustUpdated 
                    ? "2px solid " + trendColor 
                    : '1px solid var(--ggui-color-outlineVariant)',
                  boxShadow: isJustUpdated ? 'var(--ggui-shadow-md)' : 'var(--ggui-shadow-sm)',
                  backgroundColor: 'var(--ggui-color-surface)',
                  transform: isJustUpdated ? 'scale(1.02)' : 'scale(1)',
                  zIndex: isJustUpdated ? 1 : 0
                }}
              >
                <Stack gap={12}>
                  <Row justify="between" align="start">
                    <Stack gap={2}>
                      <Text variant="h3" weight="bold">{stock.symbol}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name}
                      </Text>
                    </Stack>
                    <Badge variant={isPositive ? 'success' : 'error'}>
                      {formatPercent(stock.changePercent)}
                    </Badge>
                  </Row>

                  <Row justify="between" align="end">
                    <Text variant="h2" weight="bold">
                      {formatCurrency(stock.price)}
                    </Text>
                    <Text 
                      weight="semibold" 
                      color={trendColor}
                      style={{ fontSize: 'var(--ggui-font-size-sm)' }}
                    >
                      {((stock.change || 0) > 0 ? "+" : "") + (stock.change || 0).toFixed(2)}
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </div>

        <Stack gap={16}>
          <Divider />
          <Row justify="between" align="center">
            <Row gap={8} align="center">
              <div style={{ 
                width: 8, 
                height: 8, 
                borderRadius: '50%', 
                backgroundColor: 'var(--ggui-color-success)',
                boxShadow: '0 0 8px var(--ggui-color-successContainer)'
              }} />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                System Active
              </Text>
            </Row>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdated ? lastUpdated.toLocaleTimeString() : 'Connecting...'}
            </Text>
          </Row>
        </Stack>

      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  Box,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  complete?: (data: any) => void;
}

export default function OnboardingWizard({
  avatarOptions,
  roleOptions,
  initialProfile = {},
  complete
}: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '👤',
    role: initialProfile.role || (roleOptions && roleOptions[0]) || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const steps = ['Profile Setup', 'Preferences', 'Review & Confirm'];

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = useMemo(() => {
    if (currentStep === 0) return formData.name.trim().length > 0 && isValidEmail(formData.email);
    if (currentStep === 1) return formData.role && formData.role.length > 0;
    return true;
  }, [currentStep, formData]);

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const nextStep = () => { if (currentStep < steps.length - 1 && isStepValid) setCurrentStep(s => s + 1); };
  const prevStep = () => { if (currentStep > 0) setCurrentStep(s => s - 1); };
  const handleComplete = () => { if (complete) complete(formData); };

  const progressValue = ((currentStep + 1) / steps.length) * 100;
  const progressPercent = progressValue + '%';

  const renderStepContent = () => {
    if (currentStep === 0) {
      return (
        <Stack gap={20}>
          <Heading level={3}>Tell us about yourself</Heading>
          <Stack gap={4}>
            <Text as="label" htmlFor="name" variant="label">Full Name</Text>
            <Input id="name" label="Full Name" value={formData.name} onChange={v => updateField('name', v)} required />
          </Stack>
          <Stack gap={4}>
            <Text as="label" htmlFor="email" variant="label">Email Address</Text>
            <Input id="email" label="Email Address" type="email" value={formData.email} onChange={v => updateField('email', v)} required />
          </Stack>
          <Stack gap={8}>
            <Text variant="label">Choose Avatar</Text>
            <Row gap={12} wrap="wrap">
              {avatarOptions && avatarOptions.map(a => (
                <Button key={a} variant={formData.avatar === a ? 'primary' : 'outline'} onClick={() => updateField('avatar', a)} style={{ fontSize: '32px', width: '64px', height: '64px' }}>{a}</Button>
              ))}
            </Row>
          </Stack>
        </Stack>
      );
    }
    if (currentStep === 1) {
      return (
        <Stack gap={20}>
          <Heading level={3}>Preferences</Heading>
          <Select label="Role" value={formData.role} onChange={v => updateField('role', v)} options={roleOptions ? roleOptions.map(r => ({ value: r, label: r })) : []} required />
          <Select label="Theme" value={formData.theme} onChange={v => updateField('theme', v)} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
          <Checkbox label="Email Notifications" checked={formData.emailNotifications} onChange={c => updateField('emailNotifications', c)} />
        </Stack>
      );
    }
    return (
      <Stack gap={20}>
        <Heading level={3}>Review & Confirm</Heading>
        <Card background="var(--ggui-color-surfaceVariant)" padding={16} border={false}>
          <Stack gap={16}>
            <Row gap={16} align="center">
              <Box style={{ fontSize: '48px', background: 'var(--ggui-color-surface)', borderRadius: '50%', width: '80px', height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{formData.avatar}</Box>
              <Stack><Text variant="h3">{formData.name}</Text><Text color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text></Stack>
            </Row>
            <Divider />
            <Stack gap={8}>
              <Row justify="between"><Text weight="bold">Role</Text><Text>{formData.role}</Text></Row>
              <Row justify="between"><Text weight="bold">Theme</Text><Text style={{ textTransform: 'capitalize' }}>{formData.theme}</Text></Row>
              <Row justify="between"><Text weight="bold">Notifications</Text><Text style={{ color: formData.emailNotifications ? 'var(--ggui-color-primary)' : 'var(--ggui-color-onSurfaceVariant)' }}>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text></Row>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    );
  };

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-8)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Stack gap={12}>
          <Row justify="between" align="center">
            {steps.map((label, idx) => (
              <Stack key={label} align="center" gap={4}>
                <Box style={{ width: '32px', height: '32px', borderRadius: '100%', background: idx <= currentStep ? 'var(--ggui-color-primary)' : 'var(--ggui-color-outline)', color: 'var(--ggui-color-onPrimary)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '12px', fontWeight: 'bold' }}>
                  {idx < currentStep ? <Icon name="check" size={16} /> : idx + 1}
                </Box>
                <Text variant="caption" style={{ color: idx === currentStep ? 'var(--ggui-color-primary)' : 'var(--ggui-color-onSurfaceVariant)' }}>{label}</Text>
              </Stack>
            ))}
          </Row>
          <Box style={{ height: '4px', width: '100%', background: 'var(--ggui-color-outlineVariant)', borderRadius: '4px', position: 'relative', overflow: 'hidden' }}>
            <Box style={{ position: 'absolute', height: '100%', width: progressPercent, background: 'var(--ggui-color-primary)', transition: 'width 0.3s' }} />
          </Box>
        </Stack>

        <Card padding={32} shadow="md">
          <div key={currentStep} style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: '320px', display: 'flex', flexDirection: 'column' }}>
            <Box style={{ flex: 1 }}>{renderStepContent()}</Box>
            <Divider margin={24} />
            <Row justify="between">
              <Button variant="outline" onClick={prevStep} disabled={currentStep === 0} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
              {currentStep < 2 ? (
                <Button variant="primary" onClick={nextStep} disabled={!isStepValid} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleComplete} rightIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
              )}
            </Row>
          </div>
        </Card>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to map common weather condition strings to emojis
 * if the provided prop isn't already an emoji.
 */
const getWeatherEmoji = (condition: string = '') => {
  const c = condition.toLowerCase();
  if (c.indexOf('sun') !== -1 || c.indexOf('clear') !== -1) return '☀️';
  if (c.indexOf('cloud') !== -1 || c.indexOf('overcast') !== -1) return '☁️';
  if (c.indexOf('rain') !== -1 || c.indexOf('drizzle') !== -1) return '🌧️';
  if (c.indexOf('snow') !== -1 || c.indexOf('ice') !== -1) return '❄️';
  if (c.indexOf('thunder') !== -1 || c.indexOf('storm') !== -1) return '⛈️';
  if (c.indexOf('wind') !== -1 || c.indexOf('breeze') !== -1) return '💨';
  if (c.indexOf('mist') !== -1 || c.indexOf('fog') !== -1) return '🌫️';
  // If the condition itself looks like an emoji (2-byte char), return it
  if (condition.length <= 2) return condition;
  return '⛅'; // Default fallback
};

/**
 * WeatherCard Component
 * 
 * A reusable weather display card showing current conditions and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 10,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 70, low: 60 },
    { day: 'Wed', icon: '🌧️', high: 65, low: 58 },
    { day: 'Thu', icon: '⛅', high: 68, low: 59 },
    { day: 'Fri', icon: '☀️', high: 74, low: 63 },
  ],
}: Props) {
  const currentEmoji = getWeatherEmoji(condition);

  return (
    <Card 
      padding="var(--ggui-spacing-6, 24px)" 
      shadow="md"
      border
    >
      <Stack gap={24}>
        {/* Header: City and Date Info */}
        <Stack gap={4}>
          <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
          </Text>
        </Stack>

        {/* Main Display: Large Temp and Icon */}
        <Row align="center" justify="between">
          <Stack gap={0}>
            <Text 
              weight="bold" 
              style={{ 
                fontSize: '4rem', 
                lineHeight: 1,
                color: 'var(--ggui-color-onSurface, #18181b)'
              }}
            >
              {Math.round(temperature) + '°' + unit}
            </Text>
            <Text variant="h3" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>

          <Box style={{ fontSize: '4.5rem' }}>
            {currentEmoji}
          </Box>
        </Row>

        {/* Secondary Stats: Humidity and Wind */}
        <Row justify="between" style={{ padding: '0 var(--ggui-spacing-2, 8px)' }}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
              HUMIDITY
            </Text>
            <Text variant="body" weight="semibold">
              {humidity + '%'}
            </Text>
          </Stack>

          <Divider orientation="vertical" margin={0} />

          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" weight="medium">
              WIND SPEED
            </Text>
            <Text variant="body" weight="semibold">
              {windSpeed + ' ' + (unit === 'C' ? 'km/h' : 'mph')}
            </Text>
          </Stack>
        </Row>

        <Divider margin={8} />

        {/* 5-Day Forecast Strip */}
        <Row justify="between">
          {forecast.slice(0, 5).map((item, index) => (
            <Stack key={(item.day || 'day') + index} align="center" gap={8} style={{ flex: 1 }}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day}
              </Text>

              <Box style={{ fontSize: '1.5rem' }}>
                {getWeatherEmoji(item.icon)}
              </Box>

              <Stack gap={2} align="center">
                <Text variant="caption" weight="bold">
                  {item.high + '°'}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low + '°'}
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Text, Card, Input, Button } from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  electronConfiguration?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

const CATEGORIES: Record<string, { label: string; color: string; on: string }> = {
  'alkali-metal': { label: 'Alkali Metal', color: 'var(--ggui-color-primary-100)', on: 'var(--ggui-color-onPrimaryContainer)' },
  'alkaline-earth': { label: 'Alkaline Earth', color: 'var(--ggui-color-secondary-100)', on: 'var(--ggui-color-onSecondaryContainer)' },
  'transition-metal': { label: 'Transition Metal', color: 'var(--ggui-color-tertiary-100)', on: 'var(--ggui-color-onTertiaryContainer)' },
  'post-transition-metal': { label: 'Post-Transition Metal', color: 'var(--ggui-color-info-100)', on: 'var(--ggui-color-onInfoContainer)' },
  'metalloid': { label: 'Metalloid', color: 'var(--ggui-color-warning-100)', on: 'var(--ggui-color-onWarningContainer)' },
  'nonmetal': { label: 'Nonmetal', color: 'var(--ggui-color-success-100)', on: 'var(--ggui-color-onSuccessContainer)' },
  'halogen': { label: 'Halogen', color: 'var(--ggui-color-error-100)', on: 'var(--ggui-color-onErrorContainer)' },
  'noble-gas': { label: 'Noble Gas', color: 'var(--ggui-color-neutral-100)', on: 'var(--ggui-color-onNeutralContainer)' },
  'lanthanide': { label: 'Lanthanide', color: 'var(--ggui-color-primary-200)', on: 'var(--ggui-color-onPrimaryContainer)' },
  'actinide': { label: 'Actinide', color: 'var(--ggui-color-secondary-200)', on: 'var(--ggui-color-onSecondaryContainer)' },
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [q, setQ] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filtered = useMemo(() => {
    const search = q.toLowerCase().trim();
    return elements.filter(e => e.name?.toLowerCase().includes(search) || e.symbol?.toLowerCase().includes(search));
  }, [elements, q]);

  return (
    <Stack gap="xl" padding="xl" style={{ backgroundColor: 'var(--ggui-color-surface)', minHeight: '100vh' }}>
      <Stack direction="row" align="center" justify="space-between" gap="md" style={{ flexWrap: 'wrap' }}>
        <Stack gap="xs">
          <Text variant="headline-md" weight="bold">Periodic Table</Text>
          <Text variant="body-sm" color="dimmed">Elements Explorer</Text>
        </Stack>
        <Stack gap="xs" style={{ width: 'var(--ggui-spacing-3xl)' }}>
          <Text as="label" htmlFor="search-id">Search elements</Text>
          <Input label="Search elements" id="search-id" placeholder="Filter..." value={q} onChange={setQ} />
        </Stack>
      </Stack>

      <Stack direction="row" gap="sm" style={{ flexWrap: 'wrap' }}>
        {Object.entries(CATEGORIES).map(([k, v]) => (
          <Stack key={k} direction="row" align="center" gap="xs">
            <div style={{ width: 'var(--ggui-spacing-sm)', height: 'var(--ggui-spacing-sm)', borderRadius: 'var(--ggui-radius-xs)', backgroundColor: v.color }} />
            <Text variant="label-sm">{v.label}</Text>
          </Stack>
        ))}
      </Stack>

      <div style={{ overflowX: 'auto' }}>
        <div role="grid" aria-label="Table" style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-xs)', minWidth: 'var(--ggui-spacing-5xl, 800px)' }}>
          {filtered.map((e) => {
            const cfg = CATEGORIES[e.category || ''] || { color: 'var(--ggui-color-surface-container)', on: 'var(--ggui-color-onSurface)' };
            const isSel = selected?.atomicNumber === e.atomicNumber;
            return (
              <button
                key={String(e.atomicNumber)}
                onClick={() => setSelected(e)}
                aria-pressed={isSel}
                style={{
                  gridColumn: e.col,
                  gridRow: e.row,
                  backgroundColor: cfg.color,
                  color: cfg.on,
                  border: isSel ? '2px solid var(--ggui-color-primary)' : '1px solid var(--ggui-color-outline-variant)',
                  borderRadius: 'var(--ggui-radius-sm)',
                  aspectRatio: '1/1.2',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-xs)',
                  cursor: 'pointer',
                  position: 'relative',
                  zIndex: isSel ? 10 : 1,
                  transform: isSel ? 'scale(1.1)' : 'none'
                }}
              >
                <Text variant="label-xs" style={{ fontSize: 'var(--ggui-font-size-xs)', position: 'absolute', top: 'var(--ggui-spacing-xs)', left: 'var(--ggui-spacing-xs)' }}>{e.atomicNumber}</Text>
                <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Text variant="title-md" weight="bold">{e.symbol}</Text>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {selected && (
        <Card variant="outlined" style={{ padding: 'var(--ggui-spacing-lg)' }}>
          <Stack direction="row" gap="xl" align="start" style={{ flexWrap: 'wrap' }}>
            <Stack align="center" justify="center" style={{ width: 'var(--ggui-spacing-4xl)', height: 'var(--ggui-spacing-4xl)', backgroundColor: CATEGORIES[selected.category || '']?.color || 'var(--ggui-color-surface-container)', borderRadius: 'var(--ggui-radius-md)' }}>
              <Text variant="label-md">{selected.atomicNumber}</Text>
              <Text variant="headline-md" weight="bold">{selected.symbol}</Text>
            </Stack>
            <Stack gap="sm" style={{ flex: 1, minWidth: 'var(--ggui-spacing-3xl)' }}>
              <Stack direction="row" justify="space-between" align="center">
                <Text variant="headline-sm">{selected.name}</Text>
                <Button variant="ghost" size="sm" onClick={() => setSelected(null)}>Close</Button>
              </Stack>
              <Text variant="label-md" color="dimmed" style={{ textTransform: 'uppercase' }}>{selected.category}</Text>
              <Stack gap="xs" style={{ marginTop: 'var(--ggui-spacing-sm)' }}>
                <Text variant="body-md">Weight: <b>{selected.atomicWeight} u</b></Text>
                <Text variant="body-md">Electron Config: <code>{selected.electronConfiguration}</code></Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
}

/**
 * StockTickerDashboard
 * 
 * A live stock ticker dashboard that updates prices via agent-data events.
 */
export default function StockTickerDashboard({ stocks: initialStocks = [] }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [currentTime, setCurrentTime] = useState<string>(new Date().toLocaleTimeString());

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now.toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
    }
  }, [initialStocks]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail;
      if (!detail) return;

      const type = detail.type;
      const data = detail.data;

      if (type === 'price-update' && data && data.symbol) {
        setStocks((prevStocks) => {
          return prevStocks.map((s) => {
            if (s.symbol === data.symbol) {
              return {
                ...s,
                price: typeof data.price === 'number' ? data.price : s.price,
                change: typeof data.change === 'number' ? data.change : s.change,
                changePercent: typeof data.changePercent === 'number' ? data.changePercent : s.changePercent,
              };
            }
            return s;
          });
        });
        setLastUpdated(new Date());
      }
    };

    const target: any = typeof globalThis !== 'undefined' ? globalThis : {};
    if (target.addEventListener) {
      target.addEventListener('ggui:agent-data', handleAgentData);
      return () => target.removeEventListener('ggui:agent-data', handleAgentData);
    }
  }, []);

  const renderStockCard = (stock: Stock) => {
    const isPositive = (stock.change ?? 0) >= 0;
    const colorRole = isPositive ? 'var(--ggui-color-success, #10b981)' : 'var(--ggui-color-error, #ef4444)';
    const trendPrefix = isPositive ? '+' : '';
    const displayPrice = stock.price ? stock.price.toFixed(2) : '0.00';
    const displayChange = stock.change ? stock.change.toFixed(2) : '0.00';
    const displayPercent = stock.changePercent ? stock.changePercent.toFixed(2) : '0.00';

    return (
      <Card 
        key={stock.symbol}
        variant="elevated"
        style={{ 
          padding: 'var(--ggui-spacing-4, 16px)',
          flex: '1 1 280px', 
          maxWidth: '100%',
          border: '1px solid var(--ggui-color-outlineVariant, #e5e7eb)'
        }}
      >
        <Stack direction="column" gap="var(--ggui-spacing-4, 16px)">
          <Stack direction="row" justify="space-between" align="start">
            <Stack direction="column" gap="0">
              <Text variant="heading-m" weight="bold">
                {stock.symbol || '---'}
              </Text>
              <Text variant="body-s" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>
                {stock.name || 'Unknown Company'}
              </Text>
            </Stack>
          </Stack>

          <Stack direction="column" gap="var(--ggui-spacing-1, 4px)">
            <Text variant="heading-l" weight="bold">
              {'$'}{displayPrice}
            </Text>
            <Stack direction="row" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Text 
                variant="body-m" 
                weight="medium" 
                style={{ color: colorRole }}
              >
                {trendPrefix}{displayChange}
              </Text>
              <Text 
                variant="body-m" 
                weight="medium" 
                style={{ 
                  color: 'var(--ggui-color-onPrimary, #ffffff)', 
                  backgroundColor: colorRole,
                  paddingInline: 'var(--ggui-spacing-2, 8px)',
                  paddingBlock: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-radius-s, 4px)',
                  fontSize: '0.75rem'
                }}
              >
                {trendPrefix}{displayPercent}{'%'}
              </Text>
            </Stack>
          </Stack>
        </Stack>
      </Card>
    );
  };

  return (
    <Stack 
      direction="column" 
      gap="var(--ggui-spacing-6, 24px)" 
      style={{ 
        width: '100%', 
        padding: 'var(--ggui-spacing-6, 24px)',
        backgroundColor: 'var(--ggui-color-surface, #ffffff)',
        color: 'var(--ggui-color-onSurface, #111827)',
        borderRadius: 'var(--ggui-radius-l, 12px)',
        minHeight: '100%',
        boxSizing: 'border-box'
      }}
    >
      <Stack 
        direction="row" 
        justify="space-between" 
        align="center"
        style={{ 
          borderBottom: '1px solid var(--ggui-color-outlineVariant, #e5e7eb)', 
          paddingBottom: 'var(--ggui-spacing-4, 16px)' 
        }}
      >
        <Stack direction="column" gap="0">
          <Text variant="heading-xl" weight="bold">Market Watch</Text>
          <Text variant="body-m" style={{ color: 'var(--ggui-color-onSurfaceVariant, #6b7280)' }}>
            Real-time streaming dashboard
          </Text>
        </Stack>
        <Text variant="body-m" weight="medium" style={{ color: 'var(--ggui-color-primary, #3b82f6)' }}>
          {currentTime}
        </Text>
      </Stack>

      {!stocks || stocks.length === 0 ? (
        <Stack align="center" justify="center" style={{ flexGrow: 1, padding: 'var(--ggui-spacing-10, 40px)' }}>
          <Text variant="body-l" style={{ opacity: 0.5 }}>Connecting to live market data...</Text>
        </Stack>
      ) : (
        <Stack 
          direction="row" 
          wrap="wrap" 
          gap="var(--ggui-spacing-4, 16px)"
          style={{ width: '100%' }}
        >
          {stocks.map((stock) => renderStockCard(stock))}
        </Stack>
      )}

      <Stack 
        direction="row" 
        justify="center" 
        align="center"
        style={{ 
          marginTop: 'auto', 
          paddingTop: 'var(--ggui-spacing-4, 16px)',
          borderTop: '1px solid var(--ggui-color-outlineVariant, #e5e7eb)',
          opacity: 0.7
        }}
      >
        <Text variant="body-s">
          Last updated at {lastUpdated.toLocaleTimeString()}
        </Text>
      </Stack>
    </Stack>
  );
}

