import React, { useState } from 'react';
import { Card, Stack, Text, Button, Input, Box } from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  onComplete?: (data: any) => void;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile = {}, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name || '',
    email: initialProfile.email || '',
    avatar: initialProfile.avatar || (avatarOptions && avatarOptions[0]) || '',
    role: initialProfile.role || (roleOptions && roleOptions[0]) || '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme || 'light'
  });

  const handleInputChange = (field: string, value: any) => setFormData(prev => ({ ...prev, [field]: value }));
  const isStep1Valid = formData.name.trim().length > 0 && EMAIL_REGEX.test(formData.email);

  const progress = step === 1 ? '33%' : step === 2 ? '66%' : '100%';

  return (
    <Card 
      variant="elevated" 
      padding="xl" 
      style={{ 
        maxWidth: 'var(--ggui-spacing-8xl)', 
        margin: '0 auto', 
        width: '100%',
        backgroundColor: 'var(--ggui-color-surface)',
        border: '1px solid var(--ggui-color-outline-variant)'
      }}
    >
      <Stack gap="md" marginBottom="xl">
        <Stack direction="row" align="center" justify="space-between">
          <Text variant="heading-sm" weight="bold">Setup Profile</Text>
          <Text variant="body-sm">Step {step} of 3</Text>
        </Stack>
        <Box style={{ height: 'var(--ggui-spacing-xs)', backgroundColor: 'var(--ggui-color-outline-variant)', borderRadius: 'var(--ggui-radius-full)', overflow: 'hidden' }}>
          <Box style={{ height: '100%', width: progress, backgroundColor: 'var(--ggui-color-primary)' }} />
        </Box>
      </Stack>

      <Stack gap="xl" style={{ minHeight: '350px' }}>
        {step === 1 && (
          <Stack gap="lg">
            <Stack gap="xs">
              <Text as="label" htmlFor="name-field">Full Name</Text>
              <Input id="name-field" label="Full Name" placeholder="Alex Rivera" value={formData.name} onChange={(val: string) => handleInputChange('name', val)} />
            </Stack>
            <Stack gap="xs">
              <Text as="label" htmlFor="email-field">Email Address</Text>
              <Input id="email-field" label="Email Address" type="email" placeholder="alex@example.com" value={formData.email} onChange={(val: string) => handleInputChange('email', val)} />
            </Stack>
            <Stack gap="sm">
              <Text variant="body-sm" weight="medium">Select Avatar</Text>
              <Stack direction="row" gap="sm" wrap="wrap">
                {avatarOptions.map(emoji => (
                  <Button 
                    key={emoji} 
                    variant={formData.avatar === emoji ? 'filled' : 'outline'} 
                    onClick={() => handleInputChange('avatar', emoji)} 
                    style={{ fontSize: 'var(--ggui-font-size-2xl)', width: 'var(--ggui-spacing-3xl)', height: 'var(--ggui-spacing-3xl)', padding: 0 }}
                  >
                    {emoji}
                  </Button>
                ))}
              </Stack>
            </Stack>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap="lg">
            <Stack gap="sm">
              <Text variant="body-sm" weight="medium">Select Role</Text>
              <Stack direction="row" gap="sm" wrap="wrap">
                {roleOptions.map(role => (
                  <Button 
                    key={role} 
                    variant={formData.role === role ? 'filled' : 'tonal'} 
                    size="sm"
                    onClick={() => handleInputChange('role', role)}
                  >
                    {role}
                  </Button>
                ))}
              </Stack>
            </Stack>

            <Stack direction="row" align="center" justify="space-between">
              <Stack gap="none">
                <Text weight="medium">Email Notifications</Text>
                <Text variant="body-sm" color="onSurfaceVariant">Receive updates</Text>
              </Stack>
              <Button 
                variant={formData.emailNotifications ? 'filled' : 'outline'} 
                size="sm"
                onClick={() => handleInputChange('emailNotifications', !formData.emailNotifications)}
              >
                {formData.emailNotifications ? 'Enabled' : 'Disabled'}
              </Button>
            </Stack>

            <Stack direction="row" align="center" justify="space-between">
              <Stack gap="none">
                <Text weight="medium">UI Theme</Text>
                <Text variant="body-sm" color="onSurfaceVariant">Current: {formData.theme}</Text>
              </Stack>
              <Button size="sm" variant="tonal" onClick={() => handleInputChange('theme', formData.theme === 'light' ? 'dark' : 'light')}>
                Switch Theme
              </Button>
            </Stack>
          </Stack>
        )}

        {step === 3 && (
          <Stack gap="lg">
            <Text variant="body-md" weight="bold">Review Your Profile</Text>
            <Card variant="outline" padding="md" style={{ backgroundColor: 'var(--ggui-color-surface-container-low)' }}>
              <Stack gap="md">
                <Stack direction="row" align="center" gap="md">
                  <Text style={{ fontSize: 'var(--ggui-font-size-3xl)' }}>{formData.avatar}</Text>
                  <Stack gap="none">
                    <Text weight="bold">{formData.name}</Text>
                    <Text variant="body-sm" color="onSurfaceVariant">{formData.email}</Text>
                  </Stack>
                </Stack>
                <Box style={{ height: '1px', backgroundColor: 'var(--ggui-color-outline-variant)' }} />
                <Stack gap="xs">
                  <Text variant="body-sm">Role: <b>{formData.role}</b></Text>
                  <Text variant="body-sm">Notifications: <b>{formData.emailNotifications ? 'On' : 'Off'}</b></Text>
                  <Text variant="body-sm">Theme: <b>{formData.theme}</b></Text>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}
      </Stack>

      <Stack direction="row" justify="space-between" marginTop="xl" paddingTop="md" style={{ borderTop: '1px solid var(--ggui-color-outline-variant)' }}>
        <Button variant="text" onClick={() => setStep(s => s - 1)} disabled={step === 1}>Back</Button>
        {step < 3 ? (
          <Button variant="filled" onClick={() => setStep(s => s + 1)} disabled={step === 1 && !isStep1Valid}>Next Step</Button>
        ) : (
          <Button variant="filled" onClick={() => onComplete && onComplete(formData)}>Complete Setup</Button>
        )}
      </Stack>
    </Card>
  );
}
